import React, { useState } from 'react';
import { createRoot } from 'react-dom/client';
import { Button } from '../design-system/Button/Button';
import { Card } from '../design-system/Card/Card';
import { Badge } from '../design-system/Badge/Badge';
import { Tabs } from '../design-system/Badge/Badge';
import '../theme/variables.css';

interface ScribeResult {
  subjective: string;
  objective: string;
  assessment: string;
  plan: string;
  billing_suggestions: { code: string; description: string; fee: number; confidence: number }[];
  prescription_suggestions: { drug: string; dose: string; route: string; frequency: string; duration: string; rationale: string }[];
  lab_suggestions: { test: string; urgency: string; rationale: string }[];
  referral_needed: boolean;
  referral_specialty: string;
  referral_urgency: string;
  follow_up: string;
  preventive_care_gaps: string[];
  patient_education: string[];
  mock: boolean;
}

const AI_SERVICE_URL = 'http://localhost:8000';

function Scribe() {
  const [transcript, setTranscript] = useState('');
  const [result, setResult] = useState<ScribeResult | null>(null);
  const [loading, setLoading] = useState(false);
  const [error, setError] = useState<string | null>(null);
  const [activeTab, setActiveTab] = useState('soap');
  const [edited, setEdited] = useState<Partial<ScribeResult>>({});

  const handleGenerate = async () => {
    setError(null);
    setLoading(true);
    try {
      const res = await fetch(`${AI_SERVICE_URL}/api/v1/scribe/generate`, {
        method: 'POST',
        headers: { 'Content-Type': 'application/json' },
        body: JSON.stringify({ transcript, encounter_type: 'visit' }),
      });
      if (!res.ok) throw new Error(`Server error: ${res.status}`);
      const data = await res.json();
      setResult(data);
      setEdited({});
      setActiveTab('soap');
    } catch (e: any) {
      setError(e.message || 'Failed to generate SOAP note');
    } finally {
      setLoading(false);
    }
  };

  const update = (field: keyof ScribeResult, value: any) => setEdited(p => ({ ...p, [field]: value }));

  const data = result ? { ...result, ...edited } : null;

  return (
    <div style={{ maxWidth: 900, margin: '0 auto', padding: 'var(--spacing-4)' }}>
      <h1 style={{ fontSize: 'var(--font-size-2xl)', marginBottom: 'var(--spacing-4)' }}>AI Scribe</h1>

      <Card title="Encounter Transcript">
        <p style={{ color: 'var(--color-neutral-500)', fontSize: 'var(--font-size-sm)', marginBottom: 'var(--spacing-3)' }}>
          Paste the encounter transcript below. The AI will generate a structured SOAP note, billing codes, prescriptions, and follow-up plans.
        </p>
        <textarea
          value={transcript}
          onChange={e => setTranscript(e.target.value)}
          placeholder="Paste clinical encounter transcript here...&#10;&#10;e.g. Patient John Smith, 45M, presents with cough and fever x 3 days..."
          rows={10}
          style={{ width: '100%', padding: 'var(--spacing-3)', fontSize: 'var(--font-size-base)', border: '1px solid var(--color-neutral-300)', borderRadius: 'var(--radius-md)', resize: 'vertical', fontFamily: 'var(--font-sans)' }}
        />
        <div style={{ marginTop: 'var(--spacing-3)', display: 'flex', gap: 'var(--spacing-2)', alignItems: 'center' }}>
          <Button onClick={handleGenerate} disabled={transcript.length < 20 || loading}>
            {loading ? 'Generating...' : 'Generate SOAP Note'}
          </Button>
          {data?.mock && <Badge variant="warning">Offline mode</Badge>}
        </div>
        {error && <div style={{ marginTop: 'var(--spacing-3)', padding: 'var(--spacing-3)', background: 'var(--color-error-light)', borderRadius: 'var(--radius-md)', color: 'var(--color-error)', fontSize: 'var(--font-size-sm)' }}>{error}</div>}
      </Card>

      {data && (
        <div style={{ marginTop: 'var(--spacing-4)' }}>
          <Tabs
            tabs={[
              { key: 'soap', label: 'SOAP Note' },
              { key: 'billing', label: `Billing (${data.billing_suggestions.length})` },
              { key: 'rx', label: `Prescriptions (${data.prescription_suggestions.length})` },
              { key: 'labs', label: `Labs (${data.lab_suggestions.length})` },
            ]}
            activeKey={activeTab}
            onChange={setActiveTab}
          />

          <div style={{ marginTop: 'var(--spacing-4)' }}>
            {activeTab === 'soap' && (
              <div style={{ display: 'flex', flexDirection: 'column', gap: 'var(--spacing-4)' }}>
                <SoapSection label="Subjective" value={data.subjective} onChange={v => update('subjective', v)} />
                <SoapSection label="Objective" value={data.objective} onChange={v => update('objective', v)} />
                <SoapSection label="Assessment" value={data.assessment} onChange={v => update('assessment', v)} />
                <SoapSection label="Plan" value={data.plan} onChange={v => update('plan', v)} />
                <div style={{ padding: 'var(--spacing-3)', background: 'var(--color-neutral-50)', borderRadius: 'var(--radius-md)', fontSize: 'var(--font-size-sm)', color: 'var(--color-neutral-700)' }}>
                  <strong>Follow-up:</strong> {data.follow_up || 'Not specified'}
                  {data.referral_needed && <span style={{ marginLeft: 'var(--spacing-3)', color: 'var(--color-warning)' }}>Referral: {data.referral_specialty} ({data.referral_urgency})</span>}
                </div>
              </div>
            )}

            {activeTab === 'billing' && (
              <div>
                {data.billing_suggestions.map((b, i) => (
                  <div key={i} style={{ display: 'flex', justifyContent: 'space-between', padding: 'var(--spacing-2) var(--spacing-3)', borderBottom: '1px solid var(--color-neutral-100)', alignItems: 'center' }}>
                    <div>
                      <strong>{b.code}</strong> <Badge variant="neutral">{b.description}</Badge>
                      {b.confidence >= 0.85 ? <Badge variant="success" >{Math.round(b.confidence * 100)}%</Badge> : <Badge variant="warning">{Math.round(b.confidence * 100)}%</Badge>}
                    </div>
                    <strong style={{ color: 'var(--color-primary-700)' }}>${b.fee?.toFixed(2)}</strong>
                  </div>
                ))}
              </div>
            )}

            {activeTab === 'rx' && data.prescription_suggestions.length === 0 && <p style={{ color: 'var(--color-neutral-400)' }}>No prescriptions suggested.</p>}
            {activeTab === 'rx' && data.prescription_suggestions.map((rx, i) => (
              <div key={i} style={{ padding: 'var(--spacing-3)', border: '1px solid var(--color-neutral-200)', borderRadius: 'var(--radius-md)', marginBottom: 'var(--spacing-2)' }}>
                <strong>{rx.drug} {rx.dose}</strong> — {rx.route} {rx.frequency} x {rx.duration}
                <div style={{ fontSize: 'var(--font-size-sm)', color: 'var(--color-neutral-500)', marginTop: 2 }}>{rx.rationale}</div>
              </div>
            ))}

            {activeTab === 'labs' && data.lab_suggestions.length === 0 && <p style={{ color: 'var(--color-neutral-400)' }}>No labs suggested.</p>}
            {activeTab === 'labs' && data.lab_suggestions.map((l, i) => (
              <div key={i} style={{ padding: 'var(--spacing-3)', border: '1px solid var(--color-neutral-200)', borderRadius: 'var(--radius-md)', marginBottom: 'var(--spacing-2)', display: 'flex', justifyContent: 'space-between' }}>
                <div>
                  <strong>{l.test}</strong>
                  <div style={{ fontSize: 'var(--font-size-sm)', color: 'var(--color-neutral-500)' }}>{l.rationale}</div>
                </div>
                <Badge variant={l.urgency === 'stat' ? 'error' : l.urgency === 'urgent' ? 'warning' : 'info'}>{l.urgency}</Badge>
              </div>
            ))}
          </div>
        </div>
      )}
    </div>
  );
}

function SoapSection({ label, value, onChange }: { label: string; value: string; onChange: (v: string) => void }) {
  return (
    <div>
      <h3 style={{ fontSize: 'var(--font-size-base)', fontWeight: 600, marginBottom: 'var(--spacing-1)', color: 'var(--color-primary-700)' }}>{label}</h3>
      <textarea
        value={value}
        onChange={e => onChange(e.target.value)}
        rows={3}
        style={{ width: '100%', padding: 'var(--spacing-2)', fontSize: 'var(--font-size-sm)', border: '1px solid var(--color-neutral-300)', borderRadius: 'var(--radius-md)', fontFamily: 'var(--font-sans)', resize: 'vertical' }}
      />
    </div>
  );
}

const el = document.getElementById('scribe-root');
if (el) createRoot(el).render(<Scribe />);
